using System.Text;
using TMPro;
using UnityEngine;
using UnityEngine.UI;

/// <summary>
/// HUD do Desafio activo (Sistema de Missões/Desafios, Tarefa #12): painel
/// persistente mostrado enquanto <see cref="ChallengeManager.IsActive"/> —
/// nome do desafio, cronómetro (se 'hasTimeLimit', ou tempo decorrido) e lista
/// de objectivos com progresso, actualizados a partir de
/// <see cref="ChallengeObjective.CurrentProgress"/>/<see cref="ChallengeObjective.TargetProgress"/>/<see cref="ChallengeObjective.IsComplete"/>.
///
/// Singleton com auto-fallback (mesmo padrão de MissionCompleteUI/PickupPopupUI
/// — funciona sem UI montada, apenas sem mostrar nada).
///
/// Montagem no Editor (tudo opcional — campos não atribuídos são simplesmente
/// ignorados):
/// - "panelRoot": GameObject do painel (activado/desactivado automaticamente).
/// - "iconImage" (Image): ChallengeDefinition.icon.
/// - "titleText" (TMP_Text): ChallengeDefinition.displayName.
/// - "timerText" (TMP_Text): "MM:SS" — tempo restante (hasTimeLimit) ou tempo
///   decorrido (sem limite). Vazio/inactivo se o desafio não usar cronómetro
///   no HUD (ver <see cref="showTimerWithoutLimit"/>).
/// - "objectivesText" (TMP_Text, multi-linha): uma linha por objectivo —
///   "<see cref="ChallengeObjective.displayText"/>" + " (actual/meta)" se
///   TargetProgress() != -1. Objectivos cumpridos usam
///   <see cref="completedColorHex"/> e <see cref="completedPrefix"/>; os
///   restantes usam <see cref="pendingPrefix"/>.
/// </summary>
public class ChallengeHudUI : MonoBehaviour
{
    public static ChallengeHudUI Instance { get; private set; }

    [Header("Painel")]
    [SerializeField] private GameObject panelRoot;
    [SerializeField] private Image iconImage;
    [SerializeField] private TMP_Text titleText;
    [SerializeField] private TMP_Text timerText;
    [SerializeField] private TMP_Text objectivesText;

    [Header("Cronómetro")]
    [Tooltip("Se o desafio não tiver 'hasTimeLimit', mostra o tempo decorrido (a contar para cima) em vez de esconder 'timerText'.")]
    [SerializeField] private bool showTimerWithoutLimit = true;

    [Header("Lista de Objectivos")]
    [SerializeField] private string pendingPrefix = "• ";
    [SerializeField] private string completedPrefix = "✓ ";
    [Tooltip("Cor (hex) usada nas linhas de objectivos já cumpridos.")]
    [SerializeField] private string completedColorHex = "#7CFC00";

    private bool isAutoFallback;
    private readonly StringBuilder _sb = new StringBuilder();

    private void Awake()
    {
        if (Instance != null && Instance != this)
        {
            if (Instance.isAutoFallback && !isAutoFallback)
            {
                Destroy(Instance.gameObject);
            }
            else
            {
                Destroy(gameObject);
                return;
            }
        }

        Instance = this;
        transform.SetParent(null);
        DontDestroyOnLoad(gameObject);

        if (panelRoot != null) panelRoot.SetActive(false);
    }

    [RuntimeInitializeOnLoadMethod(RuntimeInitializeLoadType.BeforeSceneLoad)]
    private static void EnsureExists()
    {
        if (Instance != null) return;
        var go = new GameObject(nameof(ChallengeHudUI) + " (Fallback)");
        var instance = go.AddComponent<ChallengeHudUI>();
        instance.isAutoFallback = true;
    }

    private void OnEnable()
    {
        ChallengeManager.OnChallengeStarted += HandleStarted;
        ChallengeManager.OnChallengeEnded += HandleEnded;
    }

    private void OnDisable()
    {
        ChallengeManager.OnChallengeStarted -= HandleStarted;
        ChallengeManager.OnChallengeEnded -= HandleEnded;
    }

    private void HandleStarted(ChallengeDefinition challenge)
    {
        if (titleText != null) titleText.text = challenge.displayName;
        if (iconImage != null)
        {
            iconImage.sprite = challenge.icon;
            iconImage.enabled = challenge.icon != null;
        }

        if (panelRoot != null) panelRoot.SetActive(true);

        RefreshObjectives(challenge);
        RefreshTimer(challenge);
    }

    private void HandleEnded(ChallengeDefinition challenge, ChallengeEndReason reason, string message)
    {
        if (panelRoot != null) panelRoot.SetActive(false);
    }

    private void Update()
    {
        var manager = ChallengeManager.Instance;
        if (manager == null || !manager.IsActive) return;

        var challenge = manager.CurrentChallenge;
        RefreshTimer(challenge);
        RefreshObjectives(challenge);
    }

    private void RefreshTimer(ChallengeDefinition challenge)
    {
        if (timerText == null) return;

        var manager = ChallengeManager.Instance;
        if (manager == null) return;

        if (challenge.hasTimeLimit)
        {
            timerText.gameObject.SetActive(true);
            timerText.text = ChallengeManager.FormatTime(manager.RemainingSeconds);
        }
        else if (showTimerWithoutLimit)
        {
            timerText.gameObject.SetActive(true);
            timerText.text = ChallengeManager.FormatTime(manager.ElapsedSeconds);
        }
        else
        {
            timerText.gameObject.SetActive(false);
        }
    }

    private void RefreshObjectives(ChallengeDefinition challenge)
    {
        if (objectivesText == null) return;
        if (challenge.objectives == null || challenge.objectives.Count == 0)
        {
            objectivesText.text = string.Empty;
            return;
        }

        _sb.Clear();

        for (int i = 0; i < challenge.objectives.Count; i++)
        {
            var objective = challenge.objectives[i];
            if (objective == null) continue;

            bool complete = objective.IsComplete();

            if (i > 0) _sb.Append('\n');

            if (complete) _sb.Append("<color=").Append(completedColorHex).Append('>');

            _sb.Append(complete ? completedPrefix : pendingPrefix);
            _sb.Append(objective.displayText);

            int target = objective.TargetProgress();
            if (target >= 0)
                _sb.Append(" (").Append(objective.CurrentProgress()).Append('/').Append(target).Append(')');

            if (complete) _sb.Append("</color>");
        }

        objectivesText.text = _sb.ToString();
    }
}
